75	export async function loginRequest(email: string, password: string): Promise<LoginResponse> {
76	  let response: Response;
77	  try {
78	    response = await fetch(`${API_BASE_URL}/auth/login`, {
79	      method: 'POST',
80	      headers: { 'Content-Type': 'application/json' },
81	      body: JSON.stringify({ email, password }),
82	    });
83	  } catch {
84	    throw new ApiError('Network error — please try again.', 0);
85	  }
86	
87	  if (response.ok) {
88	    return await response.json();
89	  }
90	
91	  const body = await response.json();
92	
93	  const message =
94	    response.status === 401
95	      ? 'Invalid email or password.'
96	      : (extractErrorMessage(body) ?? 'Login failed — please try again.');
97	
98	  throw new ApiError(message, response.status);
99	}
